import{_ as e,c as a,ag as i,o as s}from"./chunks/framework.mHuDn-wg.js";const _=JSON.parse('{"title":"bash概述","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/计算机语言/bash.md","filePath":"计算机/计算机语言/bash.md","lastUpdated":null}'),o={name:"计算机/计算机语言/bash.md"};function t(h,l,r,c,d,n){return s(),a("div",null,l[0]||(l[0]=[i('<h1 id="bash概述" tabindex="-1">bash概述 <a class="header-anchor" href="#bash概述" aria-label="Permalink to &quot;bash概述&quot;">​</a></h1><ul><li><a href="https://tldp.org/LDP/Bash-Beginners-Guide/html/sect_01_02.html" target="_blank" rel="noreferrer">bash的优点和特性</a></li><li>shell内置命令包含在shell本身中, 在shell程序内部实现, 不需要外部程序或者二进制文件来执行.</li><li>当执行脚本文件中的命令, bash将创建一个新的子bash, 当shell脚本中没有更多的行可供读取时，子shell终止。父shell将被唤醒并显示一个新的提示。</li><li>当bash启动时，它读取其配置文件 <ul><li><code>/etc/profile</code></li><li><code>~/.bash_profile</code></li><li><code>~/.bashrc</code></li></ul></li><li>Shell命令可以分为三组：shell函数，shell内置程序和系统目录中的现有命令。</li><li>Shell脚本由这些命令组成，这些命令按照shell语法进行排列。文件是逐行读取和执行的，并且应该具有逻辑结构。</li><li>构建块(building blocks)是组成脚本的基本单元, 包括基本命令, 语法, 函数, 参数...</li><li>命令的几种执行方式 <ul><li>添加执行权限<code>chmod +x script.sh</code></li><li><code>bash *.sh</code></li><li><code>source *.sh</code></li><li><code>cat *.sh | bash</code></li><li><code>bash &lt; *.sh</code></li><li>调试模式, 使用选项<code>-x</code></li></ul></li><li>环境变量: 查看当前有哪些变量<code>env</code>或<code>printenv</code></li></ul><h2 id="基础知识" tabindex="-1">基础知识 <a class="header-anchor" href="#基础知识" aria-label="Permalink to &quot;基础知识&quot;">​</a></h2><ul><li>四种变量: String, Integer, Constant, Array variables</li><li>保留变量是指那些具有特殊用途或由系统自动管理的变量，对Shell的行为和环境有重要影响。用户不应直接修改这些变量</li></ul>',4)]))}const u=e(o,[["render",t]]);export{_ as __pageData,u as default};
